const SOURCE_FAMILY_BY_SOURCE_KEY = (() => {
  const out = new Map();
  for (const [family, sourceKeys] of ENTITY_TOPIC_RECALL_FAMILY_SOURCES.entries()) {
    for (const sourceKey of sourceKeys || []) {
      if (!out.has(sourceKey)) out.set(sourceKey, family);
    }
  }
  for (const sourceKey of [
    "officialRegulatory",
    "officialOwnedMediaSources",
    "publicProductRecallSources",
    "publicRegulatoryWarningLetterSources",
    "publicEnforcementActionSources",
    "publicAdvertisingRulingsSources",
  ]) {
    out.set(sourceKey, "official");
  }
  return out;
})();
