function collectionJobDirectUrls(job = {}) {
  return uniqueExpansionTerms([
    ...(Array.isArray(job.metadata?.direct_urls) ? job.metadata.direct_urls : []),
    ...(Array.isArray(job.metadata?.directUrls) ? job.metadata.directUrls : []),
    ...(Array.isArray(job.metadata?.archive_sample_urls) ? job.metadata.archive_sample_urls : []),
    ...(Array.isArray(job.metadata?.archiveSampleUrls) ? job.metadata.archiveSampleUrls : []),
    ...(Array.isArray(job.metadata?.low_depth_urls) ? job.metadata.low_depth_urls : []),
    ...(Array.isArray(job.metadata?.lowDepthUrls) ? job.metadata.lowDepthUrls : []),
    ...(Array.isArray(job.metadata?.low_depth_comment_urls) ? job.metadata.low_depth_comment_urls : []),
    ...(Array.isArray(job.metadata?.lowDepthCommentUrls) ? job.metadata.lowDepthCommentUrls : []),
    ...(Array.isArray(job.metadata?.origin_urls) ? job.metadata.origin_urls : []),
    ...(Array.isArray(job.metadata?.originUrls) ? job.metadata.originUrls : []),
    ...(Array.isArray(job.metadata?.followup_targets) ? job.metadata.followup_targets : []),
    ...(Array.isArray(job.metadata?.followupTargets) ? job.metadata.followupTargets : []),
    ...(Array.isArray(job.metadata?.sample_urls) ? job.metadata.sample_urls : []),
    ...(Array.isArray(job.metadata?.sampleUrls) ? job.metadata.sampleUrls : []),
    ...(Array.isArray(job.metadata?.source_pack_direct_urls) ? job.metadata.source_pack_direct_urls : []),
    ...(Array.isArray(job.metadata?.sourcePackDirectUrls) ? job.metadata.sourcePackDirectUrls : []),
    ...(Array.isArray(job.entity?.direct_urls) ? job.entity.direct_urls : []),
    ...(Array.isArray(job.entity?.directUrls) ? job.entity.directUrls : []),
    ...(Array.isArray(job.entity?.archive_sample_urls) ? job.entity.archive_sample_urls : []),
    ...(Array.isArray(job.entity?.archiveSampleUrls) ? job.entity.archiveSampleUrls : []),
    ...(Array.isArray(job.entity?.low_depth_urls) ? job.entity.low_depth_urls : []),
    ...(Array.isArray(job.entity?.lowDepthUrls) ? job.entity.lowDepthUrls : []),
    ...(Array.isArray(job.entity?.low_depth_comment_urls) ? job.entity.low_depth_comment_urls : []),
    ...(Array.isArray(job.entity?.lowDepthCommentUrls) ? job.entity.lowDepthCommentUrls : []),
    ...(Array.isArray(job.entity?.origin_urls) ? job.entity.origin_urls : []),
    ...(Array.isArray(job.entity?.originUrls) ? job.entity.originUrls : []),
    ...(Array.isArray(job.entity?.followup_targets) ? job.entity.followup_targets : []),
    ...(Array.isArray(job.entity?.followupTargets) ? job.entity.followupTargets : []),
    ...(Array.isArray(job.entity?.sample_urls) ? job.entity.sample_urls : []),
    ...(Array.isArray(job.entity?.sampleUrls) ? job.entity.sampleUrls : []),
    ...(Array.isArray(job.entity?.source_pack_direct_urls) ? job.entity.source_pack_direct_urls : []),
    ...(Array.isArray(job.entity?.sourcePackDirectUrls) ? job.entity.sourcePackDirectUrls : []),
  ], 24).filter(url => /^https?:\/\//i.test(String(url || "")));
}

function collectionJobDeepCrawlDirectTargets(job = {}, keywords = []) {
  const targets = [];
  const add = (target = {}) => {
    const url = String(target.url || target.target_url || target.targetUrl || "").trim();
    if (!/^https?:\/\//i.test(url)) return;
    targets.push({
      ...target,
      url,
      title: target.title || target.label || job.label || url,
      target_type: target.target_type || target.targetType || job.entity?.target_type || "deep-crawl-article-outlink",
      source_candidate_type: target.source_candidate_type || target.sourceCandidateType || job.entity?.source_candidate_type || "direct-deep-crawl-target",
      source_candidate_url: target.source_candidate_url || target.sourceCandidateUrl || job.entity?.parent_url || job.entity?.source_chain_parent_url || "",
      source_chain_parent_url: target.source_chain_parent_url || target.sourceChainParentUrl || job.entity?.source_chain_parent_url || job.entity?.parent_url || "",
      source_chain_root_url: target.source_chain_root_url || target.sourceChainRootUrl || job.entity?.source_chain_root_url || job.entity?.root_url || job.metadata?.chain_root_url || "",
      source_chain_depth: target.source_chain_depth ?? target.sourceChainDepth ?? job.entity?.source_chain_depth ?? 0,
      source_chain_link_reason: target.source_chain_link_reason || target.sourceChainLinkReason || job.entity?.source_chain_link_reason || job.metadata?.priority_reasons || [],
      source_weight_tiers: target.source_weight_tiers || target.sourceWeightTiers || job.entity?.source_weight_tiers || [],
      keywords_checked: target.keywords_checked || target.keywordsChecked || keywords,
      priority_score: target.priority_score || target.priorityScore || job.metadata?.priority_score || job.priority || 80,
      priority_reasons: target.priority_reasons || target.priorityReasons || job.metadata?.priority_reasons || ["collection-job-direct-target"],
      force_recrawl: true,
    });
  };
  if (job.metadata?.target && typeof job.metadata.target === "object") add(job.metadata.target);
  if (job.entity?.target && typeof job.entity.target === "object") add(job.entity.target);
  for (const target of Array.isArray(job.metadata?.direct_targets) ? job.metadata.direct_targets : []) add(target);
  for (const target of Array.isArray(job.metadata?.directTargets) ? job.metadata.directTargets : []) add(target);
  for (const target of Array.isArray(job.entity?.direct_targets) ? job.entity.direct_targets : []) add(target);
  for (const target of Array.isArray(job.entity?.directTargets) ? job.entity.directTargets : []) add(target);
  add({
    url: job.entity?.target_url || job.entity?.targetUrl || job.metadata?.target_url || job.metadata?.targetUrl,
    title: job.entity?.title || job.metadata?.title || job.label,
  });
  for (const url of collectionJobDirectUrls(job)) add({ url });
  const seen = new Set();
  return targets.filter(target => {
    const key = target.url.toLowerCase();
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  }).slice(0, 12);
}

function isExplicitAuxiliaryDeepCrawlCollectionJob(job = {}) {
  if (job.source_key !== "sourceDiscoveryDeepCrawl") return false;
  const taskType = String(job.metadata?.task_type || job.entity?.task_type || "").trim();
  if (["keyword-realtime-expansion-route-followup", "deep-crawl-chain-gap-followup", "source-discovery-deep-crawl"].includes(taskType)) {
    return true;
  }
  return job.metadata?.deep_crawl_route_followup === true
    || job.metadata?.source_discovery_deep_crawl_followup === true
    || Array.isArray(job.metadata?.direct_targets)
    || Array.isArray(job.entity?.direct_targets);
}

function collectionJobDirectUrlKeywords(job = {}, limit = 8) {
  const stop = new Set([
    "www", "com", "net", "org", "io", "co", "tw", "hk", "cn", "jp", "kr", "us", "uk",
    "post", "posts", "status", "statuses", "comment", "comments", "thread", "threads",
    "watch", "video", "videos", "results", "search", "reel", "reels", "story", "stories",
    "article", "articles", "news", "amp", "html", "htm", "rss", "feed", "sitemap",
  ]);
  const out = [];
  const add = (value = "") => {
    const cleaned = String(value || "")
      .replace(/^@+/, "")
      .replace(/[_-]+/g, " ")
      .replace(/\s+/g, " ")
      .trim();
    if (!cleaned || cleaned.length < 2 || stop.has(cleaned.toLowerCase())) return;
    if (!out.includes(cleaned)) out.push(cleaned);
  };
  for (const urlValue of collectionJobDirectUrls(job)) {
    try {
      const parsed = new URL(urlValue);
      for (const key of ["q", "query", "search", "keyword", "keywords", "s"]) {
        add(parsed.searchParams.get(key) || "");
      }
      for (const segment of parsed.pathname.split(/[/?#]+/).flatMap(part => part.split(/[^A-Za-z0-9\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af@._-]+/))) {
        add(segment);
      }
      const hostParts = parsed.hostname.replace(/^www\./i, "").split(".");
      for (const part of hostParts) add(part);
    } catch {
      continue;
    }
    if (out.length >= limit) break;
  }
  return normalizeSentimentMonitorKeywords(out.slice(0, Math.max(1, Number(limit) || 8)));
}

function realtimeKeywordExpansionFollowupExecutionMetadata(job = {}, query = []) {
  if (job.metadata?.task_type !== "realtime-keyword-expansion-followup") return null;
  const source = String(job.metadata?.expansion_source || job.metadata?.expansion_sources?.[0] || "followup").trim() || "followup";
  const keyword = String(job.metadata?.query || job.entity?.query || query?.[0] || "").trim();
  const pack = {
    source_key: job.source_key || job.metadata?.source_key || job.entity?.source_key || "",
    keywords: normalizeSentimentMonitorKeywords([keyword, ...query]).slice(0, 12),
    direct_urls: collectionJobDirectUrls(job).slice(0, 12),
    match_score: Number(job.metadata?.source_pack_max_match_score || job.metadata?.source_pack_average_match_score || job.entity?.match_score || 0) || 0,
    reason: "realtime-keyword-expansion-followup-result",
    origin: "followup",
  };
  return {
    source,
    input_keywords: normalizeSentimentMonitorKeywords([keyword]),
    selected_keywords: normalizeSentimentMonitorKeywords(query.length ? query : [keyword]),
    source_query_packs: pack.keywords.length ? [pack] : [],
    direct_urls: collectionJobDirectUrls(job).slice(0, 12),
    followup: true,
    followup_job_id: job.id || null,
    followup_job_key: job.job_key || job.jobKey || "",
    followup_reason: job.reason || "",
    followup_action: job.metadata?.action || "",
    original_recommendation: job.metadata?.recommendation || job.entity?.recommendation || "",
    original_score: Number(job.metadata?.score || job.entity?.score || 0) || 0,
  };
}

