    ...(freeSourceTargetCoverageFollowupDiagnostics(job, query, result, sourceFailures) || {}),
    ...(sourceCoverageRefreshFollowupDiagnostics(job, query, result, sourceFailures) || {}),
    ...(keywordSourceFamilyCoverageFollowupDiagnostics(job, query, result, sourceFailures) || {}),
    ...(postScanRealtimeKeywordExpansionDiagnostics(job, query, result, sourceFailures) || {}),
