    ...(historicalWindowBackfillDiagnostics(job, query, result, sourceFailures) || {}),
    ...(authorPivotFollowupDiagnostics(job, query, result, sourceFailures) || {}),
    ...(authorReputationFollowupDiagnostics(job, query, result, sourceFailures) || {}),
    ...(realtimeKeywordExpansionFamilyFanoutDiagnostics(job, query, result, sourceFailures) || {}),
    ...(keywordRealtimeExpansionRouteFollowupDiagnostics(job, query, result, sourceFailures) || {}),
    ...(openSearchArchiveFeedbackFollowupDiagnostics(job, query, result, sourceFailures) || {}),
    ...(highValueEvidenceFollowupDiagnostics(job, query, result, sourceFailures) || {}),
    ...(highRiskEvidenceRevisitDiagnostics(job, query, result, sourceFailures) || {}),
    ...(highValueEvidenceCorroborationDiagnostics(job, query, result, sourceFailures) || {}),
