export function deriveSourceDiscoveryDeepCrawlEffectivenessSignals(report = {}, { maxBoost = 28 } = {}) {
  const signals = {};
  for (const item of Array.isArray(report.sources) ? report.sources : []) {
    const sourceKey = String(item.source_key || item.sourceKey || "").trim();
    if (!sourceKey) continue;
    const score = Math.max(0, Math.min(100, Number(item.score || 0) || 0));
    const evidenceCount = Math.max(0, Number(item.evidence_count || 0) || 0);
    const strongCount = Math.max(0, Number(item.strong_count || 0) || 0);
    const usableCount = Math.max(0, Number(item.usable_count || 0) || 0);
    const feedCandidateCount = Math.max(0, Number(item.feed_candidate_count || 0) || 0);
    const sitemapCandidateCount = Math.max(0, Number(item.sitemap_candidate_count || 0) || 0);
    const followupOutlinkCount = Math.max(0, Number(item.followup_outlink_count || 0) || 0);
    const sourceSearchResultCount = Math.max(0, Number(item.source_search_result_count || 0) || 0);
    const freshSourceSearchResultCount = Math.max(0, Number(item.source_search_fresh_result_count || 0) || 0);
    const mentionEndpointCount = Math.max(0, Number(item.mention_endpoint_count || 0) || 0);
    const mentionSourceCount = Math.max(0, Number(item.mention_source_count || 0) || 0);
    const commentEntrypointCount = Math.max(0, Number(item.comment_entrypoint_count || 0) || 0);
    const reviewBlockCount = Math.max(0, Number(item.review_block_count || 0) || 0);
    const structuredReferenceCount = Math.max(0, Number(item.structured_citation_count || 0) || 0)
      + Math.max(0, Number(item.structured_correction_count || 0) || 0);
    let priorityBoost = 0;
    if (score >= 72 || strongCount > 0) {
      priorityBoost = 12
        + Math.min(8, strongCount * 4 + usableCount * 2)
        + Math.min(6, evidenceCount * 2)
        + Math.min(6, feedCandidateCount + sitemapCandidateCount + followupOutlinkCount + structuredReferenceCount)
        + Math.min(5, freshSourceSearchResultCount * 2);
    } else if (score >= 52 || usableCount > 0) {
      priorityBoost = 8
        + Math.min(6, usableCount * 2 + evidenceCount)
        + Math.min(4, feedCandidateCount + sitemapCandidateCount + mentionEndpointCount + reviewBlockCount)
        + Math.min(4, freshSourceSearchResultCount * 2);
    } else if (evidenceCount > 0) {
      priorityBoost = Math.min(8, 3 + evidenceCount);
    }
    if (sourceKey === "rssFeeds" && feedCandidateCount > 0) priorityBoost += Math.min(5, feedCandidateCount);
    if (["openWebDiscovery", "duckDuckGo", "googleNews", "bingNews"].includes(sourceKey) && (sitemapCandidateCount > 0 || followupOutlinkCount > 0)) {
      priorityBoost += Math.min(5, sitemapCandidateCount + followupOutlinkCount);
    }
    if (freshSourceSearchResultCount > 0) priorityBoost += Math.min(5, freshSourceSearchResultCount);
    if (["threads", "xSearch", "bluesky", "mastodon", "reddit", "dcard", "ptt"].includes(sourceKey) && (mentionEndpointCount > 0 || commentEntrypointCount > 0 || mentionSourceCount > 0)) {
      priorityBoost += Math.min(5, mentionEndpointCount + commentEntrypointCount + mentionSourceCount);
    }
    if (["publicReviewSites", "regionalComplaintSources"].includes(sourceKey) && reviewBlockCount > 0) priorityBoost += Math.min(5, reviewBlockCount);
    priorityBoost = Math.max(0, Math.min(maxBoost, Math.round(priorityBoost)));
    signals[sourceKey] = {
      sourceKey,
      score,
      priorityBoost,
      budgetBoost: priorityBoost > 0 ? Math.min(0.3, (priorityBoost + Math.min(10, evidenceCount + strongCount * 2)) / 100) : 0,
      evidenceCount,
      strongCount,
      usableCount,
      highQualityCount: Number(item.high_quality_count || 0) || 0,
      averageQualityScore: Number(item.average_quality_score || 0) || 0,
      bestQualityScore: Number(item.best_quality_score || 0) || 0,
      bestQualityLabel: item.best_quality_label || "",
      feedCandidateCount,
      sitemapCandidateCount,
      outlinkCount: Number(item.outlink_count || 0) || 0,
      followupOutlinkCount,
      sourceSearchResultCount,
      freshSourceSearchResultCount,
      commentEntrypointCount,
      mentionEndpointCount,
      mentionSourceCount,
      reviewBlockCount,
      structuredReferenceCount,
      entityMentionCount: Number(item.entity_mention_count || 0) || 0,
      keywordHitCount: Number(item.keyword_hit_count || 0) || 0,
      targetTypes: Array.isArray(item.target_types) ? item.target_types.slice(0, 12) : [],
      candidateTypes: Array.isArray(item.candidate_types) ? item.candidate_types.slice(0, 12) : [],
      sourceWeightTiers: Array.isArray(item.source_weight_tiers) ? item.source_weight_tiers.slice(0, 12) : [],
      qualityReasons: Array.isArray(item.quality_reasons) ? item.quality_reasons.slice(0, 16) : [],
      hosts: Array.isArray(item.hosts) ? item.hosts.slice(0, 12) : [],
      sampleUrls: Array.isArray(item.sample_urls) ? item.sample_urls.slice(0, 12) : [],
      suggestedKeywords: normalizeSentimentMonitorKeywords(item.suggested_keywords || item.sample_keywords || []).slice(0, 16),
      recommendation: item.recommendation || (priorityBoost >= 16 ? "promote-source-discovery-deep-crawl-source" : "watch-source-discovery-deep-crawl-source"),
    };
  }
  return Object.fromEntries(Object.entries(signals)
    .sort((a, b) => b[1].priorityBoost - a[1].priorityBoost || b[1].score - a[1].score || a[0].localeCompare(b[0])));
}

function collectionOperationsJobStats(jobs = [], now = Date.now()) {
  const byStatus = {};
  const byTaskType = {};
  const bySource = new Map();
  const byDuePendingTaskType = {};
  const byDuePendingSource = {};
  const duePending = [];
  const staleRunning = [];
  const retryable = [];
  const terminalFailures = [];
  for (const job of Array.isArray(jobs) ? jobs : []) {
    const status = String(job.status || "unknown");
    const sourceKey = String(job.source_key || "unknown");
    const taskType = collectionOperationsJobTaskType(job);
    byStatus[status] = (byStatus[status] || 0) + 1;
    byTaskType[taskType] = (byTaskType[taskType] || 0) + 1;
    const source = bySource.get(sourceKey) || {
      source_key: sourceKey,
      total: 0,
      pending: 0,
      due_pending: 0,
      running: 0,
      stale_running: 0,
      retryable: 0,
      failed: 0,
      partial: 0,
      throttled: 0,
      cooldown: 0,
    };
    source.total += 1;
    if (status === "pending") source.pending += 1;
    if (status === "running") source.running += 1;
    if (status === "failed") source.failed += 1;
    if (status === "partial") source.partial += 1;
    if (status === "throttled") source.throttled += 1;
    if (status === "cooldown") source.cooldown += 1;
    const scheduledMs = new Date(job.scheduled_at || job.created_at || 0).getTime();
    const startedMs = new Date(job.started_at || job.updated_at || job.created_at || 0).getTime();
    const due = status === "pending" && Number.isFinite(scheduledMs) && scheduledMs <= Number(now);
    const stale = status === "running" && Number.isFinite(startedMs) && Number(now) - startedMs > 30 * 60 * 1000;
    const retryableJob = ["failed", "partial", "cooldown", "throttled", "interval"].includes(status)
      && Number(job.attempt_count || 0) < Number(job.max_attempts || 0);
    if (due) {
      source.due_pending += 1;
      byDuePendingTaskType[taskType] = (byDuePendingTaskType[taskType] || 0) + 1;
      byDuePendingSource[sourceKey] = (byDuePendingSource[sourceKey] || 0) + 1;
      duePending.push(job);
    }
    if (stale) {
      source.stale_running += 1;
      staleRunning.push(job);
    }
    if (retryableJob) {
      source.retryable += 1;
      retryable.push(job);
    }
    if (["failed", "partial", "throttled", "cooldown"].includes(status)) terminalFailures.push(job);
    bySource.set(sourceKey, source);
  }
  return {
    byStatus,
    byTaskType,
    byDuePendingTaskType,
    byDuePendingSource,
    bySource,
    duePending,
    staleRunning,
    retryable,
    terminalFailures,
  };
}

function collectionOperationsSourceStatus(item = {}, jobStats = {}, { now = Date.now(), staleMultiplier = 3 } = {}) {
  const intervalMinutes = Math.max(1, Number(item.scan_interval_minutes || 0) || 1);
  const lastSuccessMs = new Date(item.last_success_at || "").getTime();
  const lastScanMs = new Date(item.last_scan_at || "").getTime();
  const hasSuccess = Number.isFinite(lastSuccessMs);
  const hasScan = Number.isFinite(lastScanMs);
  const ageMinutes = hasSuccess ? Math.floor((Number(now) - lastSuccessMs) / 60000) : null;
  const scanAgeMinutes = hasScan ? Math.floor((Number(now) - lastScanMs) / 60000) : null;
  const staleAfterMinutes = Math.max(intervalMinutes * Math.max(1, Number(staleMultiplier) || 3), item.realtime ? 15 : 60);
  const severelyStaleAfterMinutes = Math.max(staleAfterMinutes * 2, intervalMinutes * 6);
  const issues = [];
  if (item.enabled === false) issues.push("disabled");
  if (item.status === "cooldown") issues.push("source-cooldown");
  if (item.status === "throttled") issues.push("domain-throttle");
  if (item.status === "due") issues.push("due-source");
  if (item.enabled !== false && !hasSuccess) issues.push("no-success-yet");
  if (hasSuccess && ageMinutes > severelyStaleAfterMinutes) issues.push("severely-stale-success");
  else if (hasSuccess && ageMinutes > staleAfterMinutes) issues.push("stale-success");
  if (item.should_scan && !item.due) issues.push("signal-triggered-scan");
  if (Number(jobStats.due_pending || 0) > 0) issues.push("due-pending-jobs");
  if (Number(jobStats.stale_running || 0) > 0) issues.push("stale-running-jobs");
  if (Number(jobStats.retryable || 0) > 0) issues.push("retryable-failures");
  if (item.action === "wait-source-quality-repair") issues.push("quality-repair-needed");
  if (item.action === "wait-source-quality-backoff") issues.push("quality-backoff");
  let health = "healthy";
  if (issues.includes("disabled")) health = "disabled";
  else if (issues.some(issue => ["stale-running-jobs", "severely-stale-success", "no-success-yet"].includes(issue))) health = "critical";
  else if (issues.some(issue => ["due-pending-jobs", "retryable-failures", "stale-success", "source-cooldown", "domain-throttle", "quality-repair-needed"].includes(issue))) health = "degraded";
  else if (issues.length) health = "watch";
  const recommended = [];
  if (issues.includes("due-pending-jobs") || issues.includes("retryable-failures")) recommended.push("execute-due-retry-jobs");
  if (item.should_scan || item.due || issues.includes("stale-success") || issues.includes("no-success-yet")) recommended.push("run-continuous-collection");
  if (issues.includes("quality-repair-needed") || issues.includes("quality-backoff")) recommended.push("review-source-quality-policy");
  if (issues.includes("source-cooldown") || issues.includes("domain-throttle")) recommended.push("respect-backoff-or-switch-alternate-source");
  if (issues.includes("disabled")) recommended.push("review-disabled-source");
  return {
    source_key: item.source_key,
    label: item.label,
    source_type: item.source_type,
    source_family: item.keyword_family_coverage_signal?.families?.[0] || "",
    enabled: item.enabled,
    realtime: item.realtime,
    health,
    issues,
    recommendation: recommended[0] || "keep-monitoring",
    recommended_actions: [...new Set(recommended.length ? recommended : ["keep-monitoring"])],
    action: item.action,
    should_scan: item.should_scan,
    due: item.due,
    status: item.status,
    priority_score: item.priority_score,
    priority_reasons: item.priority_reasons || [],
    scan_interval_minutes: intervalMinutes,
    last_scan_at: item.last_scan_at,
    last_success_at: item.last_success_at,
    last_error: item.last_error,
    age_minutes: ageMinutes,
    scan_age_minutes: scanAgeMinutes,
    stale_after_minutes: staleAfterMinutes,
    waiting_ms: item.waiting_ms || 0,
    next_scan_at: item.next_scan_at,
    job_backlog: {
      total: Number(jobStats.total || 0),
      pending: Number(jobStats.pending || 0),
      due_pending: Number(jobStats.due_pending || 0),
      running: Number(jobStats.running || 0),
      stale_running: Number(jobStats.stale_running || 0),
      retryable: Number(jobStats.retryable || 0),
      failed: Number(jobStats.failed || 0),
      partial: Number(jobStats.partial || 0),
      throttled: Number(jobStats.throttled || 0),
      cooldown: Number(jobStats.cooldown || 0),
    },
  };
}

export function getSentimentCollectionOperationsReport({
  mode = SCAN_MODE_FAST,
  searchSettings = null,
  maxSources = 8,
  retryLimit = 20,
  staleMultiplier = 3,
  includeJobDetails = false,
  includeSourceDetails = false,
  includePlanDetails = false,
  now = Date.now(),
} = {}) {
  const plan = planSentimentContinuousCollection({
    mode,
    searchSettings,
    maxSources,
    retryLimit,
    now,
  });
  const jobs = listSentimentCollectionJobs({ limit: 500 });
  const jobStats = collectionOperationsJobStats(jobs, now);
  const sources = (plan.sources || []).map(item => collectionOperationsSourceStatus(
    item,
    jobStats.bySource.get(item.source_key) || {},
    { now, staleMultiplier },
  )).sort((a, b) => {
    const rank = { critical: 0, degraded: 1, watch: 2, healthy: 3, disabled: 4 };
    return (rank[a.health] ?? 9) - (rank[b.health] ?? 9)
      || b.priority_score - a.priority_score
      || a.source_key.localeCompare(b.source_key);
  });
  const actionable = sources.filter(item => !["healthy", "disabled"].includes(item.health));
  const ready = new Set(plan.ready_scan_sources || []);
  const dueRetryJobs = jobStats.duePending.filter(job => String(job.reason || "").includes("retry"));
  const compactJobs = jobsList => includeJobDetails ? jobsList : jobsList.map(compactCollectionOperationJob);
  const compactSources = sourceList => includeSourceDetails ? sourceList : sourceList.map(compactCollectionOperationSource);
  const duePendingTaskTypes = topCollectionOperationCounts(jobStats.byDuePendingTaskType, 20);
  const recommendedExecuteDuePayloads = collectionOperationsExecuteDuePayloads(jobStats, { limit: 8 });
  return {
    ok: true,
    generated_at: new Date(now).toISOString(),
    mode: plan.mode,
    summary: {
      total_sources: sources.length,
      healthy_sources: sources.filter(item => item.health === "healthy").length,
      watch_sources: sources.filter(item => item.health === "watch").length,
      degraded_sources: sources.filter(item => item.health === "degraded").length,
      critical_sources: sources.filter(item => item.health === "critical").length,
      disabled_sources: sources.filter(item => item.health === "disabled").length,
      ready_scan_sources: plan.summary?.ready_scan_sources || ready.size,
      due_retry_jobs: dueRetryJobs.length,
      due_pending_jobs: jobStats.duePending.length,
      stale_running_jobs: jobStats.staleRunning.length,
      retryable_jobs: jobStats.retryable.length,
      backlog_jobs: jobs.filter(job => ["pending", "running"].includes(String(job.status || ""))).length,
      terminal_failure_jobs: jobStats.terminalFailures.length,
      by_job_status: jobStats.byStatus,
      by_job_task_type: jobStats.byTaskType,
      due_pending_by_task_type: duePendingTaskTypes,
      due_pending_by_source: topCollectionOperationCounts(jobStats.byDuePendingSource, 20),
      highest_priority_source: sources[0]?.source_key || "",
      recommended_execute_due_payloads: recommendedExecuteDuePayloads,
      recommended_next_action: dueRetryJobs.length || recommendedExecuteDuePayloads.length
        ? "execute-due-retry-jobs"
        : ready.size || actionable.some(item => item.recommended_actions.includes("run-continuous-collection"))
          ? "run-continuous-collection"
          : actionable.some(item => item.recommended_actions.includes("review-source-quality-policy"))
            ? "review-source-quality-policy"
            : "keep-monitoring",
    },
    ready_scan_sources: plan.ready_scan_sources || [],
    detail_mode: {
      jobs: includeJobDetails ? "full" : "compact",
      sources: includeSourceDetails ? "full" : "compact",
      plan: includePlanDetails ? "full" : "summary",
    },
    actionable_sources: compactSources(actionable.slice(0, 30)),
    sources: compactSources(sources),
    job_backlog: {
      detail_mode: includeJobDetails ? "full" : "compact",
      due_pending_by_task_type: duePendingTaskTypes,
      due_pending_by_source: topCollectionOperationCounts(jobStats.byDuePendingSource, 20),
      recommended_execute_due_payloads: recommendedExecuteDuePayloads,
      due_pending: compactJobs(jobStats.duePending.slice(0, 30)),
      stale_running: compactJobs(jobStats.staleRunning.slice(0, 30)),
      retryable: compactJobs(jobStats.retryable.slice(0, 30)),
    },
    continuous_plan_summary: plan.summary,
    retry_plan: includePlanDetails ? plan.retry_plan : null,
  };
}

function collectionOperationSourceInputFromRecord(source = {}, { now = Date.now() } = {}) {
  const intervalMinutes = Math.max(1, Number(source.scan_interval_minutes || 0) || 1);
  const lastScanMs = new Date(source.last_scan_at || "").getTime();
  const due = source.enabled !== false && (!Number.isFinite(lastScanMs) || Number(now) - lastScanMs >= intervalMinutes * 60 * 1000);
  return {
    ...source,
    realtime: source.config?.realtime === true || source.source_type === "social",
    due,
    should_scan: due,
    status: source.last_error ? "error" : due ? "due" : "ok",
    action: due ? "scan-due-source" : "wait-scan-interval",
    priority_score: Number(source.priority || 0),
  };
}

function collectionOperationSourceRows(searchSettings = null) {
  const search = readSentimentSearchSettings(searchSettings);
  const allowedSources = Array.isArray(search?.sources) && search.sources.length
    ? new Set(search.sources.map(source => String(source || "").trim()).filter(Boolean))
    : null;
  return listSentimentSources().filter(source => !allowedSources || allowedSources.has(source.source_key));
}

export function getSentimentCollectionOperationsFastReport({
  mode = SCAN_MODE_FAST,
  searchSettings = null,
  staleMultiplier = 3,
  includeJobDetails = false,
  includeSourceDetails = false,
  now = Date.now(),
} = {}) {
  const normalizedMode = normalizeSentimentScanMode(mode);
  const jobs = listSentimentCollectionJobs({ limit: 500 });
  const jobStats = collectionOperationsJobStats(jobs, now);
  const sources = collectionOperationSourceRows(searchSettings).map(source => collectionOperationsSourceStatus(
    collectionOperationSourceInputFromRecord(source, { now }),
    jobStats.bySource.get(source.source_key) || {},
    { now, staleMultiplier },
  )).sort((a, b) => {
    const rank = { critical: 0, degraded: 1, watch: 2, healthy: 3, disabled: 4 };
    return (rank[a.health] ?? 9) - (rank[b.health] ?? 9)
      || b.priority_score - a.priority_score
      || a.source_key.localeCompare(b.source_key);
  });
  const actionable = sources.filter(item => !["healthy", "disabled"].includes(item.health));
  const readyScanSources = sources.filter(source => source.enabled !== false && source.due).map(source => source.source_key);
  const dueRetryJobs = jobStats.duePending.filter(job => String(job.reason || "").includes("retry"));
  const compactJobs = jobsList => includeJobDetails ? jobsList : jobsList.map(compactCollectionOperationJob);
  const compactSources = sourceList => includeSourceDetails ? sourceList : sourceList.map(compactCollectionOperationSource);
  const duePendingTaskTypes = topCollectionOperationCounts(jobStats.byDuePendingTaskType, 20);
  const recommendedExecuteDuePayloads = collectionOperationsExecuteDuePayloads(jobStats, { limit: 8 });
  return {
    ok: true,
    fast_summary: true,
    generated_at: new Date(now).toISOString(),
    mode: normalizedMode,
    summary: {
      total_sources: sources.length,
      healthy_sources: sources.filter(item => item.health === "healthy").length,
      watch_sources: sources.filter(item => item.health === "watch").length,
      degraded_sources: sources.filter(item => item.health === "degraded").length,
      critical_sources: sources.filter(item => item.health === "critical").length,
      disabled_sources: sources.filter(item => item.health === "disabled").length,
      ready_scan_sources: readyScanSources.length,
      due_retry_jobs: dueRetryJobs.length,
      due_pending_jobs: jobStats.duePending.length,
      stale_running_jobs: jobStats.staleRunning.length,
      retryable_jobs: jobStats.retryable.length,
      backlog_jobs: jobs.filter(job => ["pending", "running"].includes(String(job.status || ""))).length,
      terminal_failure_jobs: jobStats.terminalFailures.length,
      by_job_status: jobStats.byStatus,
      by_job_task_type: jobStats.byTaskType,
      due_pending_by_task_type: duePendingTaskTypes,
      due_pending_by_source: topCollectionOperationCounts(jobStats.byDuePendingSource, 20),
      highest_priority_source: sources[0]?.source_key || "",
      recommended_execute_due_payloads: recommendedExecuteDuePayloads,
      recommended_next_action: dueRetryJobs.length || recommendedExecuteDuePayloads.length
        ? "execute-due-retry-jobs"
        : readyScanSources.length || actionable.some(item => item.recommended_actions.includes("run-continuous-collection"))
          ? "run-continuous-collection"
          : actionable.some(item => item.recommended_actions.includes("review-source-quality-policy"))
            ? "review-source-quality-policy"
            : "keep-monitoring",
    },
    ready_scan_sources: readyScanSources,
    detail_mode: {
      jobs: includeJobDetails ? "full" : "compact",
      sources: includeSourceDetails ? "full" : "compact",
      plan: "fast-summary",
    },
    actionable_sources: compactSources(actionable.slice(0, 30)),
    sources: compactSources(sources),
    job_backlog: {
      detail_mode: includeJobDetails ? "full" : "compact",
      due_pending_by_task_type: duePendingTaskTypes,
      due_pending_by_source: topCollectionOperationCounts(jobStats.byDuePendingSource, 20),
      recommended_execute_due_payloads: recommendedExecuteDuePayloads,
      due_pending: compactJobs(jobStats.duePending.slice(0, 30)),
      stale_running: compactJobs(jobStats.staleRunning.slice(0, 30)),
      retryable: compactJobs(jobStats.retryable.slice(0, 30)),
    },
    continuous_plan_summary: {
      mode: normalizedMode,
      ready_scan_sources: readyScanSources.length,
      source_count: sources.length,
      fast_summary: true,
    },
    retry_plan: null,
  };
}

