export function configureSentimentRunner({ bus, log, notificationSettings, searchSettings, aiSettings } = {}) {
  activeRunner = createScraperRunner({
    bus: safeBus(bus),
    log: log || fallbackLog(),
    notificationSettings,
    searchSettings,
    aiSettings,
  });
  return activeRunner;
}

export async function runSentimentScanNow({ reason = "manual", mode = SCAN_MODE_FAST, sources = null, days = null, keywords = null } = {}) {
  if (inFlight) return inFlight;
  if (!activeRunner) configureSentimentRunner();

  monitorState = { ...monitorState, running: true, lastError: null };
  inFlight = activeRunner({ mode: normalizeSentimentScanMode(mode), reason, sources, keywords })
    .then(result => {
      const scanDays = Math.max(1, Math.min(365, Number(days || 0) || 30));
      lastScanResult = { ...result, reason, days: scanDays, scanDays, finishedAt: new Date().toISOString() };
      monitorState = {
        ...monitorState,
        running: false,
        lastRun: lastScanResult,
        nextRunAt: monitorState.enabled
          ? new Date(Date.now() + monitorState.intervalMs).toISOString()
          : null,
      };
      return monitorState.lastRun;
    })
    .catch(err => {
      monitorState = {
        ...monitorState,
        running: false,
        lastError: err?.message || String(err),
        nextRunAt: monitorState.enabled
          ? new Date(Date.now() + monitorState.intervalMs).toISOString()
          : null,
      };
      throw err;
    })
    .finally(() => { inFlight = null; });
  return inFlight;
}

function continuousCollectionRunPublicView(run = null) {
  if (!run) return null;
  return {
    id: run.id,
    status: run.status,
    accepted: run.accepted !== false,
    mode: run.mode,
    created_at: run.created_at,
    started_at: run.started_at,
    finished_at: run.finished_at,
    duration_ms: run.duration_ms,
    options: run.options,
    result: run.result,
    error: run.error,
  };
}

function trimContinuousCollectionRunHistory() {
  const runs = [...continuousCollectionRuns.values()]
    .sort((a, b) => Date.parse(b.created_at || 0) - Date.parse(a.created_at || 0));
  for (const run of runs.slice(CONTINUOUS_COLLECTION_RUN_HISTORY_LIMIT)) {
    continuousCollectionRuns.delete(run.id);
  }
}

function activeContinuousCollectionRun() {
  return [...continuousCollectionRuns.values()]
    .find(run => run.status === "running" || run.status === "queued") || null;
}

function createContinuousCollectionRunId() {
  return `continuous-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
}

export function listSentimentContinuousCollectionRuns({ limit = 20 } = {}) {
  const safeLimit = Math.max(1, Math.min(CONTINUOUS_COLLECTION_RUN_HISTORY_LIMIT, Number(limit) || 20));
  return {
    ok: true,
    runs: [...continuousCollectionRuns.values()]
      .sort((a, b) => Date.parse(b.created_at || 0) - Date.parse(a.created_at || 0))
      .slice(0, safeLimit)
      .map(continuousCollectionRunPublicView),
  };
}

export function getSentimentContinuousCollectionRun(id = "") {
  const run = continuousCollectionRuns.get(String(id || ""));
  return {
    ok: Boolean(run),
    run: continuousCollectionRunPublicView(run),
  };
}

export function startSentimentContinuousCollectionRun(options = {}) {
  const allowConcurrent = options.allowConcurrent === true;
  const existing = allowConcurrent ? null : activeContinuousCollectionRun();
  if (existing) {
    return {
      ok: true,
      accepted: false,
      already_running: true,
      reason: "continuous-collection-run-already-running",
      run: continuousCollectionRunPublicView(existing),
    };
  }

  const now = Date.now();
  const run = {
    id: createContinuousCollectionRunId(),
    status: "queued",
    accepted: true,
    mode: normalizeSentimentScanMode(options.mode || SCAN_MODE_FAST),
    created_at: new Date(now).toISOString(),
    started_at: null,
    finished_at: null,
    duration_ms: null,
    options: {
      ...options,
      searchSettings: options.searchSettings ? "[route-search-settings]" : null,
      log: undefined,
    },
    result: null,
    error: "",
  };
  continuousCollectionRuns.set(run.id, run);
  trimContinuousCollectionRunHistory();

  Promise.resolve().then(async () => {
    const startedAt = Date.now();
    run.status = "running";
    run.started_at = new Date(startedAt).toISOString();
    try {
      if (options.deferContinuousCollectionExecution === true) {
        run.result = {
          ok: true,
          deferred: true,
          reason: options.deferContinuousCollectionReason || "continuous-collection-execution-deferred",
          mode: run.mode,
          sourceCoverageRefreshStage: {
            timed_out: false,
            stage: "source-coverage-refresh-followups",
            timeout_ms: 0,
            skipped: true,
            deferred: true,
          },
        };
      } else {
        run.result = await executeSentimentContinuousCollectionCycle(options);
      }
      run.status = "success";
    } catch (err) {
      run.status = "failed";
      run.error = err?.message || String(err);
    } finally {
      run.finished_at = new Date().toISOString();
      run.duration_ms = Math.max(0, Date.parse(run.finished_at) - startedAt);
    }
  });

  return {
    ok: true,
    accepted: true,
    already_running: false,
    run: continuousCollectionRunPublicView(run),
  };
}

export async function executeDueSentimentCollectionJobDrain({
  batches = 1,
  limit = 5,
  concurrency = 1,
  collectionOptions = {},
  collectionJobTimeoutMs = null,
  now = Date.now(),
  searchSettings = null,
  log = null,
} = {}) {
  const safeBatches = Math.max(1, Math.min(5, Number(batches) || 1));
  const safeLimit = Math.max(1, Math.min(25, Number(limit) || 5));
  const safeConcurrency = Math.max(1, Math.min(8, Number(concurrency) || 1, safeLimit));
  const batchResults = [];
  const jobs = [];
  let executed = 0;
  let total = 0;
  let events = 0;
  let alerts = 0;
  let stoppedReason = "";
  for (let index = 0; index < safeBatches; index += 1) {
    const result = await executeDueSentimentCollectionJobs({
      ...collectionOptions,
      limit: safeLimit,
      concurrency: safeConcurrency,
      collectionJobTimeoutMs,
      now: now + index,
      searchSettings,
      log,
    });
    const selectedCount = Number(result.dueJobSelection?.selected_count || result.executed || 0);
    batchResults.push({
      batch: index + 1,
      ok: result.ok !== false,
      executed: result.executed || 0,
      total: result.total || 0,
      events: result.events || 0,
      alerts: result.alerts || 0,
      dueJobSelection: result.dueJobSelection || null,
      selected_sources: result.dueJobSelection?.selected_sources || [],
      selected_task_types: result.dueJobSelection?.selected_task_types || [],
    });
    executed += Number(result.executed || 0);
    total += Number(result.total || 0);
    events += Number(result.events || 0);
    alerts += Number(result.alerts || 0);
    jobs.push(...(Array.isArray(result.jobs) ? result.jobs : []));
    if (selectedCount <= 0) {
      stoppedReason = "no-due-collection-jobs";
      break;
    }
    if (selectedCount < safeLimit) {
      stoppedReason = "drained-before-requested-batches";
      break;
    }
  }
  const selectedSources = new Set();
  const selectedTaskTypes = new Set();
  for (const batch of batchResults) {
    for (const source of batch.selected_sources || []) selectedSources.add(source);
    for (const type of batch.selected_task_types || []) selectedTaskTypes.add(type);
  }
  return {
    ok: true,
    executed,
    total,
    events,
    alerts,
    jobs,
    reason: stoppedReason || (batchResults.length >= safeBatches ? "requested-drain-batches-complete" : ""),
    backlog_drain: {
      requested_batches: safeBatches,
      executed_batches: batchResults.length,
      execution_limit: safeLimit,
      execution_concurrency: safeConcurrency,
      selected_source_count: selectedSources.size,
      selected_task_type_count: selectedTaskTypes.size,
      selected_sources: [...selectedSources].slice(0, 30),
      selected_task_types: [...selectedTaskTypes].slice(0, 30),
      stopped_reason: stoppedReason || "",
      batches: batchResults,
    },
  };
}

